8	const TENANT_ID = process.env.AZURE_TENANT_ID;
9	const CLIENT_ID = process.env.AZURE_CLIENT_ID;
10	
11	// Lazy-init so tests can inject env before the module loads
12	let _jwks = null;
13	function getJwksClient() {
14	  if (!_jwks) {
15	    _jwks = jwksClient({
16	      jwksUri: `https://login.microsoftonline.com/${TENANT_ID}/discovery/v2.0/keys`,
17	      cache: true,
18	      cacheMaxEntries: 5,
19	      cacheMaxAge: 10 * 60 * 1000, // 10 min
20	    });
21	  }
22	  return _jwks;
23	}
24	
25	function _getSigningKey(kid) {
26	  return new Promise((resolve, reject) => {
27	    getJwksClient().getSigningKey(kid, (err, key) => {
28	      if (err) return reject(err);
29	      resolve(key.getPublicKey());
30	    });
31	  });
32	}
33	
34	/**
35	 * Validate an Azure AD ID token.
36	 * Returns the decoded payload on success; throws on failure.
37	 */
38	async function verifyAzureToken(idToken) {
39	  const decoded = jwt.decode(idToken, { complete: true });
40	  if (!decoded) throw new Error('Invalid token format');
41	
42	  const signingKey = await _getSigningKey(decoded.header.kid);
43	
44	  const payload = jwt.verify(idToken, signingKey, {
45	    algorithms: ['RS256'],
46	    audience: CLIENT_ID,
47	    issuer: `https://login.microsoftonline.com/${TENANT_ID}/v2.0`,
48	  });
49	  return payload;
50	}
