6	/**
7	 * Return { firstName, name, email, photoUrl } for the authenticated user.
8	 * Accepts the decoded JWT ({ user_id, role }). Factory (vendor) users carry a
9	 * vendor_id in user_id and live in the `vendor` table, not `users`, so we must
10	 * branch on role — otherwise a vendor's id is looked up in `users`, misses, and
11	 * the endpoint 404s. Returns null if the user is not found.
12	 */
13	UserService.getProfile = async ({ user_id: userId, role }) => {
14	  if (role === 'vendor') {
15	    const vendor = await sql.vendor.findOne({
16	      where: { vendor_id: userId },
17	      attributes: ['vendor_id', 'vendor_name', 'vendor_lastname', 'vendor_email', 'vendor_profile_photo'],
18	    });
19	    if (!vendor) return null;
20	    return {
21	      firstName: vendor.vendor_name || '',
22	      name: `${vendor.vendor_name || ''} ${vendor.vendor_lastname || ''}`.trim(),
23	      email: vendor.vendor_email || '',
24	      photoUrl: vendor.vendor_profile_photo || null,
25	    };
26	  }
27	  const user = await sql.users.findOne({
28	    where: { id: userId },
29	    attributes: ['id', 'name', 'lastname', 'email', 'profile_photo'],
30	  });
31	  if (!user) return null;
32	  return {
33	    firstName: user.name || '',
34	    name: `${user.name || ''} ${user.lastname || ''}`.trim(),
35	    email: user.email || '',
36	    photoUrl: user.profile_photo || null,
37	  };
38	};
39	
40	/**
41	 * Persist a new photo URL for the authenticated user. Returns the URL.
42	 * Branches on role so vendor avatars land in vendor.vendor_profile_photo
43	 * instead of writing to a non-existent users row.
44	 */
45	UserService.updateProfilePhoto = async ({ user_id: userId, role }, photoUrl) => {
46	  if (role === 'vendor') {
47	    await sql.vendor.update(
48	      { vendor_profile_photo: photoUrl },
49	      { where: { vendor_id: userId } }
50	    );
51	  } else {
52	    await sql.users.update(
53	      { profile_photo: photoUrl },
54	      { where: { id: userId } }
55	    );
56	  }
57	  return photoUrl;
58	};
59	
60	module.exports = UserService;
