396	/**
397	 * Persist the Section 301 lookup to app_settings, then read it back and verify it
398	 * round-trips intact before the caller reports success.
399	 *
400	 * Why this exists: the upload handlers used to return the *parsed* summary right
401	 * after `AppSettingService.set(...)` without confirming the write actually landed.
402	 * So a save that silently failed, was rejected, or was truncated by the store still
403	 * reported "N codes loaded" to the admin — while `getSection301Status` then read back
404	 * nothing (or unparseable JSON) and every `lookupSection301` 404'd ("The requested
405	 * item was not found"). Verifying the round-trip turns a silent false-success into a
406	 * loud, specific error that names what actually happened.
407	 *
408	 * @param {object} lookup parsed `{ HTS: { list, rate, description } }` map
409	 * @returns {number} the verified code count read back from the store
410	 * @throws {Error} if the value is missing, unparseable, or short on read-back
411	 */
412	async function persistSection301Lookup(lookup) {
413	  const expected = Object.keys(lookup).length;
414	  await AppSettingService.set('section301_lookup', JSON.stringify(lookup));
415	
416	  const raw = await AppSettingService.get('section301_lookup');
417	  if (!raw) {
418	    throw new Error(
419	      `Section 301 save failed: parsed ${expected} codes but read back nothing. ` +
420	      `The app_settings store did not retain the value.`
421	    );
422	  }
423	  let stored;
424	  try {
425	    stored = JSON.parse(raw);
426	  } catch (e) {
427	    throw new Error(
428	      `Section 301 save failed: parsed ${expected} codes but the stored value did not ` +
429	      `parse back as JSON (read-back length ${raw.length}). It was likely truncated or ` +
430	      `corrupted in storage.`
431	    );
432	  }
433	  const got = Object.keys(stored).length;
434	  if (got !== expected) {
435	    throw new Error(
436	      `Section 301 save failed: parsed ${expected} codes but only ${got} read back. ` +
437	      `The app_settings store truncated or rejected part of the value.`
438	    );
439	  }
440	  return got;
441	}
