482	/**
483	 * POST /api/admin/section301/upload-csv
484	 * Preferred over the PDF uploader: takes a USTR Section 301 CSV (`HTS,Description,List`
485	 * columns; preamble and repeated headers tolerated). Parsing is column-addressed,
486	 * so codes are never silently mis-assigned to the wrong list the way the regex
487	 * PDF parser can be. List 4B rows are imported with rate 0 and labeled
488	 * "List 4B (suspended)" because that list was announced but never enacted.
489	 *
490	 * Multipart field name: "csv".
491	 *
492	 * Response:
493	 *   { codesFound, lists, skipped, conflicts, lineErrors }
494	 */
495	async function uploadSection301Csv(req, res) {
496	  try {
497	    if (!req.file || !req.file.buffer) {
498	      return res.status(400).json({ error: 'No CSV file uploaded. Send as multipart field "csv".' });
499	    }
500	    const lower = req.file.originalname.toLowerCase();
501	    const looksCsv = req.file.mimetype.includes('csv')
502	                  || req.file.mimetype.includes('text/plain')
503	                  || lower.endsWith('.csv');
504	    if (!looksCsv) {
505	      return res.status(400).json({ error: 'Uploaded file must be a .csv.' });
506	    }
507	
508	    const text = req.file.buffer.toString('utf8');
509	    const { lookup, summary } = parseSection301Csv(text);
510	
511	    if (summary.codesFound === 0) {
512	      return res.status(422).json({
513	        error: 'No HTS codes were found in the CSV. Check the file has "HTS,Description,List" columns.',
514	        summary,
515	      });
516	    }
517	
518	    // Verify the write actually round-trips before reporting success. A clean parse
519	    // summary alone does not prove the data persisted (see persistSection301Lookup).
520	    const storedCount = await persistSection301Lookup(lookup);
521	    res.json({ ...summary, storedCount });
522	  } catch (err) {
523	    console.error('[section301/upload-csv] error:', err.message);
524	    res.status(500).json({ error: err.message });
525	  }
526	}
